import sys
import boto3

def create_subscription(topic, endpoint):
    sns = boto3.client('sns')
    response = sns.subscribe(TopicArn=topic, Protocol='https', Endpoint=endpoint)
    print("Subscription created with ARN: ", response['SubscriptionArn'])

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python create_subscription.py <topic_arn> <endpoint>")
        sys.exit(1)

    topic = sys.argv[1]
    endpoint = sys.argv[2]
    create_subscription(topic, endpoint)